Web FormsBlazor with Repeater <pre><code>&lt;asp:Repeater ID="rptItems" runat="server" OnItemDataBound="rptItems_ItemDataBound"&gt;
    &lt;ItemTemplate&gt;
        &lt;div&gt;&lt;%# Eval("Name") %&gt;&lt;/div&gt;
        &lt;asp:Label ID="lblPrice" runat="server" /&gt;
    &lt;/ItemTemplate&gt;
&lt;/asp:Repeater&gt;
</code></pre> <pre><code>protected void Page_Load(object sender, EventArgs e)
{
    if (!IsPostBack)
    {
        rptItems.DataSource = GetItems();
        rptItems.DataBind();
    }
}

protected void rptItems_ItemDataBound(object sender, RepeaterItemEventArgs e)
{
    if (e.Item.ItemType == ListItemType.Item || e.Item.ItemType == ListItemType.AlternatingItem)
    {
        decimal price = (decimal)DataBinder.Eval(e.Item.DataItem, "Price");
        Label lblPrice = (Label)e.Item.FindControl("lblPrice");
        lblPrice.Text = price.ToString("C");
    }
}
</code></pre> <pre><code>&lt;Repeater Items="items"&gt;
    &lt;ItemTemplate&gt;
        &lt;div&gt;@context.Name&lt;/div&gt;
        &lt;Label Text="@context.Price.ToString("C")" /&gt;
    &lt;/ItemTemplate&gt;
&lt;/Repeater&gt;

@code {
    private List&lt;Item&gt;? items;

    protected override async Task OnInitializedAsync()
    {
        items = await GetItemsAsync();
    }

    private async Task&lt;List&lt;Item&gt;&gt; GetItemsAsync()
    {
        // Load items
        return new();
    }
}

class Item
{
    public string Name { get; set; } = "";
    public decimal Price { get; set; }
}
</code></pre>

Web FormsBlazor <pre><code>&lt;asp:DropDownList ID="ddlCategory" runat="server" 
                  OnSelectedIndexChanged="ddlCategory_SelectedIndexChanged"
                  AutoPostBack="true" /&gt;
&lt;asp:Repeater ID="rptProducts" runat="server"&gt;
    &lt;ItemTemplate&gt;
        &lt;div&gt;&lt;%# Eval("Name") %&gt;&lt;/div&gt;
    &lt;/ItemTemplate&gt;
&lt;/asp:Repeater&gt;
</code></pre> <pre><code>protected void ddlCategory_SelectedIndexChanged(object sender, EventArgs e)
{
    int categoryId = int.Parse(ddlCategory.SelectedValue);
    LoadProductsForCategory(categoryId);
}

private void LoadProductsForCategory(int categoryId)
{
    rptProducts.DataSource = GetProducts(categoryId);
    rptProducts.DataBind();
}
</code></pre> <pre><code>&lt;DropDownList Items="categories" 
              @bind-Value="selectedCategoryId" 
              OnChange="HandleCategoryChange" /&gt;

&lt;Repeater Items="products"&gt;
    &lt;ItemTemplate&gt;
        &lt;div&gt;@context.Name&lt;/div&gt;
    &lt;/ItemTemplate&gt;
&lt;/Repeater&gt;

@code {
    private List&lt;Category&gt; categories = new();
    private List&lt;Product&gt; products = new();
    private string selectedCategoryId = "";

    protected override async Task OnInitializedAsync()
    {
        categories = await GetCategoriesAsync();
    }

    private async Task HandleCategoryChange()
    {
        if (int.TryParse(selectedCategoryId, out int categoryId))
        {
            products = await GetProductsAsync(categoryId);
        }
    }

    private async Task&lt;List&lt;Category&gt;&gt; GetCategoriesAsync() { /* ... */ return new(); }
    private async Task&lt;List&lt;Product&gt;&gt; GetProductsAsync(int categoryId) { /* ... */ return new(); }
}
</code></pre> <p>Key differences: - ✅ No separate <code>ItemDataBound</code> event — use <code>@context</code> in the template - ✅ No <code>FindControl</code> — data is directly accessible - ✅ No casting — types are strongly checked - ✅ Reactive — updating <code>products</code> or <code>selectedCategoryId</code> automatically re-renders</p>

